// --- SQL Validation & Sanitization ---

sealed trait ValidationError
case class ForbiddenKeyword(keyword: String) extends ValidationError
case class ForbiddenPattern(pattern: String) extends ValidationError
case class UnauthorizedTable(table: String) extends ValidationError
case class QueryTooComplex(reason: String) extends ValidationError
case class InvalidSyntax(reason: String) extends ValidationError

class SqlValidator(allowedDatabases: Set[String], allowedTables: Set[String]) {

  // Forbidden SQL keywords/commands that should never appear in read-only analytics queries
  private val forbiddenKeywords: Set[String] = Set(
    "DROP", "DELETE", "INSERT", "UPDATE", "ALTER", "CREATE", "REPLACE",
    "TRUNCATE", "GRANT", "REVOKE", "MERGE", "UPSERT",
    "SET", "RESET", "ADD JAR", "ADD FILE", "ADD ARCHIVE",
    "LOAD DATA", "EXPORT", "IMPORT", "MSCK", "REFRESH",
    "CACHE TABLE", "UNCACHE", "CLEAR CACHE",
    "DESCRIBE FUNCTION", "SHOW FUNCTIONS",
    "CREATE FUNCTION", "DROP FUNCTION", "CREATE TEMPORARY FUNCTION"
  )

  // Patterns that indicate file system access or code execution
  private val forbiddenPatterns: Seq[String] = Seq(
    """(?i)INTO\s+OUTFILE""",
    """(?i)LOAD\s+DATA""",
    """(?i)FROM\s+['"]?(file|hdfs|s3a?|gs|abfss?|wasbs?)://""",
    """(?i)USING\s+(jdbc|csv|parquet|orc|json|text)\s+OPTIONS""",
    """(?i)LOCATION\s+['"]""",
    """(?i)reflect\s*\(""",
    """(?i)java_method\s*\(""",
    """(?i)stack\s*\(""",
    """(?i)xpath\s*\(""",
    """(?i)/\*.*\*/""",   // Block comments can hide malicious content
    """(?i);\s*\w""",      // Multiple statements
    """(?i)LATERAL\s+VIEW\s+explode\s*\(\s*sequence""" // Resource bomb
  )

  private val maxQueryLength = 10000
  private val maxJoinCount = 5
  private val maxSubqueryDepth = 3

  def validate(sql: String): Either[Seq[ValidationError], String] = {
    val errors = scala.collection.mutable.ListBuffer[ValidationError]()
    val normalizedSql = sql.trim.replaceAll("\\s+", " ")

    // Check query length
    if (normalizedSql.length > maxQueryLength) {
      errors += QueryTooComplex(s"Query exceeds maximum length of $maxQueryLength characters")
    }

    // Check for multiple statements (semicolon-separated)
    if (normalizedSql.count(_ == ';') > 1 ||
        (normalizedSql.contains(';') && normalizedSql.indexOf(';') < normalizedSql.length - 1)) {
      errors += ForbiddenPattern("Multiple SQL statements are not allowed")
    }

    // Check forbidden keywords
    val upperSql = normalizedSql.toUpperCase
    forbiddenKeywords.foreach { keyword =>
      val pattern = s"(?i)\\b${java.util.regex.Pattern.quote(keyword)}\\b".r
      if (pattern.findFirstIn(normalizedSql).isDefined) {
        errors += ForbiddenKeyword(keyword)
      }
    }

    // Check forbidden patterns
    forbiddenPatterns.foreach { pattern =>
      if (pattern.r.findFirstIn(normalizedSql).isDefined) {
        errors += ForbiddenPattern(s"Forbidden pattern detected: $pattern")
      }
    }

    // Must start with SELECT or WITH (CTE)
    if (!upperSql.startsWith("SELECT") && !upperSql.startsWith("WITH") && !upperSql.startsWith("SHOW") && !upperSql.startsWith("DESCRIBE")) {
      errors += InvalidSyntax("Only SELECT, WITH (CTE), SHOW TABLES, and DESCRIBE queries are allowed")
    }

    // Check join count
    val joinCount = "(?i)\\bJOIN\\b".r.findAllIn(normalizedSql).length
    if (joinCount > maxJoinCount) {
      errors += QueryTooComplex(s"Query has $joinCount JOINs, maximum allowed is $maxJoinCount")
    }

    // Check subquery depth
    val maxParenDepth = computeMaxParenDepth(normalizedSql)
    if (maxParenDepth > maxSubqueryDepth * 2) { // rough heuristic
      errors += QueryTooComplex(s"Query nesting appears too deep (depth: $maxParenDepth)")
    }

    // Validate table references against allowlist
    val tableRefs = extractTableReferences(normalizedSql)
    tableRefs.foreach { table =>
      val qualifiedTable = if (table.contains(".")) table else table
      val isAllowed = allowedTables.exists(allowed =>
        allowed.equalsIgnoreCase(qualifiedTable) ||
        allowed.equalsIgnoreCase(qualifiedTable.split("\\.").last)
      )
      if (!isAllowed && !isCommonKeyword(table)) {
        errors += UnauthorizedTable(table)
      }
    }

    if (errors.isEmpty) Right(normalizedSql.stripSuffix(";").trim)
    else Left(errors.toSeq)
  }

  private def computeMaxParenDepth(sql: String): Int = {
    var maxDepth = 0
    var currentDepth = 0
    sql.foreach {
      case '(' =>
        currentDepth += 1
        maxDepth = Math.max(maxDepth, currentDepth)
      case ')' =>
        currentDepth -= 1
      case _ =>
    }
    maxDepth
  }

  private def extractTableReferences(sql: String): Seq[String] = {
    val fromPattern = """(?i)\bFROM\s+([a-zA-Z_][\w.]*)\b""".r
    val joinPattern = """(?i)\bJOIN\s+([a-zA-Z_][\w.]*)\b""".r

    val fromTables = fromPattern.findAllMatchIn(sql).map(_.group(1)).toSeq
    val joinTables = joinPattern.findAllMatchIn(sql).map(_.group(1)).toSeq

    (fromTables ++ joinTables).distinct
  }

  private def isCommonKeyword(word: String): Boolean = {
    val keywords = Set("SELECT", "FROM", "WHERE", "GROUP", "ORDER", "HAVING",
      "LIMIT", "UNION", "ALL", "DISTINCT", "AS", "ON", "AND", "OR", "NOT",
      "IN", "EXISTS", "BETWEEN", "LIKE", "IS", "NULL", "TRUE", "FALSE",
      "CASE", "WHEN", "THEN", "ELSE", "END", "LATERAL", "VIEW", "DUAL")
    keywords.contains(word.toUpperCase)
  }
}

// --- Query Execution Engine ---

class SecureQueryExecutor(spark: SparkSession, validator: SqlValidator) {

  import spark.implicits._

  private val defaultMaxRows = 10000
  private val absoluteMaxRows = 100000

  def executeQuery(request: QueryRequest): Either[QueryError, QueryResult] = {
    val queryId = UUID.randomUUID().toString
    val startTime = System.currentTimeMillis()

    // Step 1: Validate the SQL
    validator.validate(request.sql) match {
      case Left(errors) =>
        val errorMessages = errors.map {
          case ForbiddenKeyword(kw) => s"Forbidden keyword: $kw"
          case ForbiddenPattern(p) => s"Forbidden pattern detected"
          case UnauthorizedTable(t) => s"Unauthorized table access: $t"
          case QueryTooComplex(r) => s"Query too complex: $r"
          case InvalidSyntax(r) => s"Invalid syntax: $r"
        }
        Left(QueryError(queryId, "VALIDATION_ERROR", errorMessages.mkString("; "), "ValidationError"))

      case Right(sanitizedSql) =>
        executeValidatedQuery(queryId, sanitizedSql, request, startTime)
    }
  }

  private def executeValidatedQuery(
    queryId: String,
    sql: String,
    request: QueryRequest,
    startTime: Long
  ): Either[QueryError, QueryResult] = {

    val maxRows = Math.min(
      request.maxRows.getOrElse(defaultMaxRows),
      absoluteMaxRows
    )

    // Wrap query with LIMIT to prevent unbounded result sets
    val limitedSql = if (sql.toUpperCase.contains("LIMIT")) {
      sql
    } else {
      s"$sql LIMIT $maxRows"
    }

    Try {
      // Set per-query resource limits
      spark.conf.set("spark.sql.autoBroadcastJoinThreshold", "10485760") // 10MB
      spark.conf.set("spark.sql.adaptive.enabled", "true")

      // Use a dedicated fair scheduler pool for user queries
      spark.sparkContext.setLocalProperty("spark.scheduler.pool", "user_queries")
      spark.sparkContext.setLocalProperty("spark.job.description", s"User query: $queryId")

      // Execute with explain plan first to check estimated cost
      val df = spark.sql(limitedSql)

      // Collect results
      val rows = df.take(maxRows)
      val columns = df.columns.toSeq
      val data = rows.map { row =>
        columns.zipWithIndex.map { case (col, idx) =>
          col -> (if (row.isNullAt(idx)) null else row.get(idx))
        }.toMap
      }.toSeq

      val executionTimeMs = System.currentTimeMillis() - startTime

      val warnings = scala.collection.mutable.ListBuffer[String]()
      if (rows.length >= maxRows) {
        warnings += s"Results truncated to $maxRows rows"
      }
      if (executionTimeMs > 30000) {
        warnings += "Query took longer than 30 seconds. Consider optimizing."
      }

      QueryResult(
        queryId = queryId,
        status = "SUCCESS",
        rowCount = rows.length.toLong,
        columns = columns,
        data = data,
        executionTimeMs = executionTimeMs,
        warnings = warnings.toSeq
      )
    } match {
      case Success(result) =>
        logQueryExecution(queryId, request, "SUCCESS", result.executionTimeMs)
        Right(result)
      case Failure(ex) =>
        val executionTimeMs = System.currentTimeMillis() - startTime
        logQueryExecution(queryId, request, "FAILED", executionTimeMs)
        Left(QueryError(
          queryId = queryId,
          errorMessage = sanitizeErrorMessage(ex.getMessage),
          errorType = ex.getClass.getSimpleName
        ))
    }
  }

  // Don't leak internal details in error messages
  private def sanitizeErrorMessage(message: String): String = {
    if (message == null) return "Unknown error occurred"
    // Remove file paths, internal class names, stack traces
    val sanitized = message
      .replaceAll("(?i)(hdfs|s3a?|file|gs)://[^\\s]+", "[PATH_REDACTED]")
      .replaceAll("at [a-zA-Z0-9$.]+\\([^)]+\\)", "")
      .take(500)
    sanitized
  }

  private def logQueryExecution(
    queryId: String,
    request: QueryRequest,
    status: String,
    executionTimeMs: Long
  ): Unit = {
    // Audit logging - write to a secure audit table
    Try {
      import spark.implicits._
      val auditRecord = Seq((
        queryId,
        request.userId,
        request.sql.take(2000), // Truncate for storage
        status,
        executionTimeMs,
        Instant.now().toString
      )).toDF("query_id", "user_id", "sql_text", "status", "execution_time_ms", "timestamp")

      auditRecord.write.mode("append").saveAsTable("audit.query_log")
    }.recover {
      case ex: Throwable =>
        // Log to application logger as fallback
        println(s"AUDIT [$queryId] user=${request.userId} status=$status time=${executionTimeMs}ms")
    }
  }
}

// --- Rate Limiter ---

class QueryRateLimiter(maxQueriesPerMinute: Int = 30) {
  private val queryTimestamps = scala.collection.concurrent.TrieMap[String, List[Long]]()

  def checkRateLimit(userId: String): Boolean = {
    val now = System.currentTimeMillis()
    val oneMinuteAgo = now - 60000

    val timestamps = queryTimestamps.getOrElse(userId, List.empty)
    val recentTimestamps = timestamps.filter(_ > oneMinuteAgo)

    if (recentTimestamps.length >= maxQueriesPerMinute) {
      false
    } else {
      queryTimestamps.update(userId, recentTimestamps :+ now)
      true
    }
  }
}

