// --- API Layer (using simple HTTP for demonstration) ---

class AnalyticsQueryService(spark: SparkSession) {

  private val authService = new AuthorizationService()
  private val rateLimiter = new QueryRateLimiter(maxQueriesPerMinute = 30)

  def handleQueryRequest(requestBody: String): String = {
    import org.json4s._
    import org.json4s.jackson.JsonMethods._
    import org.json4s.jackson.Serialization
    import org.json4s.jackson.Serialization.write

    implicit val formats: Formats = DefaultFormats

    Try {
      val json = parse(requestBody)
      val userId = (json \ "userId").extract[String]
      val sql = (json \ "sql").extract[String]
      val maxRows = (json \ "maxRows").extractOpt[Int]

      // Step 1: Authenticate & Authorize
      val permissions = authService.getUserPermissions(userId) match {
        case Some(p) => p
        case None =>
          return write(Map("error" -> "Unauthorized", "status" -> "AUTH_ERROR"))
      }

      // Step 2: Rate limiting
      if (!rateLimiter.checkRateLimit(userId)) {
        return write(Map(
          "error" -> "Rate limit exceeded. Maximum 30 queries per minute.",
          "status" -> "RATE_LIMITED"
        ))
      }

      // Step 3: Create per-user validator with their allowed tables
      val validator = new SqlValidator(
        allowedDatabases = permissions.allowedDatabases,
        allowedTables = permissions.allowedTables
      )

      // Step 4: Create executor and run
      val executor = new SecureQueryExecutor(spark, validator)
      val request = QueryRequest(
        userId = userId,
        sql = sql,
        maxRows = maxRows.map(r => Math.min(r, permissions.maxRowsAllowed))
      )

      executor.executeQuery(request) match {
        case Right(result) => write(result)
        case Left(error) => write(error)
      }
    } match {
      case Success(response) => response
      case Failure(ex) =>
        s"""{"error": "Invalid request format", "status": "BAD_REQUEST"}"""
    }
  }
}

